let peData = [], jeData = [];
if (data.series.length >= 2) {
  const peS = data.series.find(s => s.name === 'PE' || s.fields[0]?.name === 'PE');
  const jeS = data.series.find(s => s.name === 'JE' || s.fields[0]?.name === 'JE');
  if (peS && peS.fields.length >= 2) {
    const times = peS.fields.find(f => f.name === 'time' || f.name === '_time');
    const vals = peS.fields.find(f => f.name !== 'time' && f.name !== '_time' && f.name !== 'machine_id');
    if (times && vals) {
      for (let i = 0; i < Math.min(times.values.length, 500); i++) {
        peData.push([new Date(times.values[i]).getTime(), vals.values[i]]);
      }
    }
  }
  if (jeS && jeS.fields.length >= 2) {
    const times = jeS.fields.find(f => f.name === 'time' || f.name === '_time');
    const vals = jeS.fields.find(f => f.name !== 'time' && f.name !== '_time' && f.name !== 'machine_id');
    if (times && vals) {
      for (let i = 0; i < Math.min(times.values.length, 500); i++) {
        jeData.push([new Date(times.values[i]).getTime(), vals.values[i]]);
      }
    }
  }
}
